import React from "react";

export default function About(){

  return(

    <div id="about" className="section">

      <h2>About CampusBeacon</h2>

      <p>

      CampusBeacon is a simple platform designed to help
      students recover lost belongings across campus.

      Instead of relying on physical notice boards or
      word of mouth, our system allows students to post
      lost or found items quickly.

      Our goal is to make campus communities more
      connected and helpful.

      </p>

    </div>

  );

}
